import Loading from '@/app/loading';
import BackToMainPageButton from '@/components/BackToMainPageButton';
import { Technology } from '@/types/Technology';
import Image from 'next/image';
import { Suspense } from 'react';

export default async function ProjectPage({
  params
}: PageProps<'/project/[slug]'>) {
  const { slug } = await params;

  const response = await fetch(`${process.env.API_URL}/projects/${slug}`);
  const data = await response.json();
  const { data: project } = data;
  const { technologies } = project;
  console.log(project.technologies);

  const {}

  return (
    <>
      <header className="p-6">
        <BackToMainPageButton />
      </header>
      <Suspense fallback={<Loading />}>
        <section className="flex flex-col items-center gap-4 p-6">
          <h1 className="inline border-b border-b-primary p-4 text-wrap text-gray dark:text-white">
            {project.projectName}
          </h1>
          <div className="flex gap-4">
            {project.githubLink && (
              <a
                href={project.githubLink}
                target="_blank"
                rel="noopener noreferrer"
              >
                GitHub
              </a>
            )}
            {project.projectLink && (
              <a
                href={project.projectLink}
                target="_blank"
                rel="noopener noreferrer"
              >
                Demo
              </a>
            )}
          </div>
          <p>{project.description}</p>
          <ul className="flex flex-col justify-center gap-2">
            {technologies.map(
              (tech: {
                id: string;
                projectId: string;
                technologyId: string;
                technology: Technology;
              }) => (
                <li key={tech.id}>
                  <h4>{tech.technology.name}</h4>
                  <Image
                    src={tech.technology.logo?.imageLink}
                    alt={`${tech.technology.name} logo`}
                    width={50}
                    height={50}
                  />
                </li>
              )
            )}
          </ul>
          <Image
            src={
              project.image?.imageLink ??
              'https://ito-group.com/wp-content/uploads/2025/04/no-image.jpg'
            }
            alt={project.projectName}
            width={600}
            height={400}
            className="rounded"
          />
        </section>
      </Suspense>
    </>
  );
}
